from dataclasses import dataclass
from typing import Optional


@dataclass
class SignOffDecision:
    decision_id: str
    decision_type: str       # "SCOPE", "BEHAVIOR_SPEC", "SAFETY", "LEGAL", "DESIGN", "FINAL"
    accountable_role: str
    responsible_role: str
    criteria_met: list[str]  # criteria that were verified
    criteria_failed: list[str]  # criteria that were not met
    status: str              # "APPROVED" | "BLOCKED" | "PENDING"
    signed_off_at: Optional[str] = None   # ISO-8601
    notes: str = ""

    @property
    def is_approved(self) -> bool:
        return self.status == "APPROVED" and not self.criteria_failed

    def can_proceed(self) -> tuple[bool, str]:
        if self.status == "APPROVED" and not self.criteria_failed:
            return True, f"Approved by {self.accountable_role}"
        if self.criteria_failed:
            return False, f"Failed criteria: {'; '.join(self.criteria_failed)}"
        return False, f"Status: {self.status}"

from dataclasses import dataclass, field
from typing import Optional


REQUIRED_DECISIONS = [
    "SCOPE",
    "BEHAVIOR_SPEC",
    "SAFETY",
    "LEGAL",
    "DESIGN",
    "EVAL_GATE",
    "FINAL",
]


@dataclass
class SignOffTracker:
    flow_id: str
    decisions: dict[str, SignOffDecision] = field(default_factory=dict)

    def record(self, decision: SignOffDecision) -> None:
        self.decisions[decision.decision_type] = decision

    def pending_decisions(self) -> list[str]:
        approved = {k for k, v in self.decisions.items() if v.is_approved}
        return [d for d in REQUIRED_DECISIONS if d not in approved]

    def blocked_decisions(self) -> list[SignOffDecision]:
        return [
            v for v in self.decisions.values()
            if v.status == "BLOCKED"
        ]

    def is_fully_signed_off(self) -> bool:
        return (
            not self.pending_decisions()
            and not self.blocked_decisions()
        )

    def gate4_eligible(self) -> tuple[bool, list[str]]:
        """Gate 4 requires SCOPE, BEHAVIOR_SPEC, SAFETY, LEGAL, DESIGN all APPROVED."""
        pre_gate4 = ["SCOPE", "BEHAVIOR_SPEC", "SAFETY", "LEGAL", "DESIGN"]
        missing = [d for d in pre_gate4 if d not in self.decisions or not self.decisions[d].is_approved]
        return len(missing) == 0, missing

    def summary(self) -> dict:
        return {
            "flow_id": self.flow_id,
            "pending": self.pending_decisions(),
            "blocked": [d.decision_type for d in self.blocked_decisions()],
            "gate4_eligible": self.gate4_eligible()[0],
            "fully_signed_off": self.is_fully_signed_off(),
        }

from dataclasses import dataclass


@dataclass
class DecisionSequencing:
    """
    Models which sign-off decisions can run in parallel.
    Returns a list of parallel batches — each batch runs concurrently,
    the next batch starts only when the current one is complete.
    """
    PHASES: list[list[str]] = None

    def __post_init__(self):
        self.PHASES = [
            ["SCOPE"],                        # Phase 1: Must be first
            ["BEHAVIOR_SPEC"],               # Phase 2: Depends on scope
            ["SAFETY", "LEGAL", "EVAL_GATE"],  # Phase 3: All parallel
            ["DESIGN"],                      # Phase 4: After safety (safety reviewer co-signs design)
            ["FINAL"],                       # Phase 5: Gate 4 — after all prior
            ["HANDOFF_FREEZE"],              # Phase 6: After Gate 4
        ]

    def current_phase(self, tracker: "SignOffTracker") -> int:
        """Returns the index of the first phase with pending decisions."""
        for i, phase in enumerate(self.PHASES):
            if any(d not in tracker.decisions or not tracker.decisions[d].is_approved for d in phase):
                return i
        return len(self.PHASES)  # all done

    def decisions_to_pursue_now(self, tracker: "SignOffTracker") -> list[str]:
        phase_idx = self.current_phase(tracker)
        if phase_idx >= len(self.PHASES):
            return []
        return [
            d for d in self.PHASES[phase_idx]
            if d not in tracker.decisions or not tracker.decisions[d].is_approved
        ]

from dataclasses import dataclass
import json


@dataclass
class AuditReport:
    """Produces a regulatory-audit-ready summary of all sign-off decisions."""
    tracker: SignOffTracker
    flow_id: str
    feature_name: str
    regulated_frameworks: list[str]  # e.g. ["EU_AI_ACT_HIGH_RISK", "HIPAA"]

    def to_audit_record(self) -> dict:
        return {
            "flow_id": self.flow_id,
            "feature_name": self.feature_name,
            "regulated_frameworks": self.regulated_frameworks,
            "decisions": [
                {
                    "decision_type": k,
                    "accountable_role": v.accountable_role,
                    "status": v.status,
                    "signed_off_at": v.signed_off_at,
                    "criteria_met": v.criteria_met,
                    "criteria_failed": v.criteria_failed,
                    "notes": v.notes,
                }
                for k, v in self.tracker.decisions.items()
            ],
            "fully_signed_off": self.tracker.is_fully_signed_off(),
            "generated_at": "2025-07-01T00:00:00Z",  # stamp after workflow
        }

    def to_json(self, indent: int = 2) -> str:
        return json.dumps(self.to_audit_record(), indent=indent)

    def missing_for_audit(self) -> list[str]:
        """Returns decisions that are required but missing signed_off_at timestamp."""
        return [
            k for k, v in self.tracker.decisions.items()
            if v.is_approved and not v.signed_off_at
        ]
